51: version_tuple getRuntimeVersion() {
52:   // MIOpen doesn't include runtime version info before 2.3.0
53: #if (MIOPEN_VERSION_MAJOR > 2) || \
54:     (MIOPEN_VERSION_MAJOR == 2 && MIOPEN_VERSION_MINOR > 2)
55:   size_t major, minor, patch;
56:   miopenGetVersion(&major, &minor, &patch);
57:   return version_tuple(major, minor, patch);
58: #else
59:   return getCompileVersion();
60: #endif
61: }
