63: size_t getVersionInt() {
64:   // miopen version is MAJOR*1000000 + MINOR*1000 + PATCH
65:   auto [major, minor, patch] = getRuntimeVersion();
66:   return major * 1000000 + minor * 1000 + patch;
67: }
68: 
