    for dtype in (torch.half, torch.bfloat16):
        x = torch.rand(1, 16, 124, 1282, 722, dtype=dtype, device=device)
        m = torch.nn.Conv3d(
            16,
            16,
            kernel_size=(1, 3, 3),
            padding=0,
            stride=1,
            bias=False,
            dtype=dtype,
            device=device,
        )
        with torch.backends.cudnn.flags(enabled=False):
            yref = m(x)
        y = m(x)
        self.assertEqual(yref, y)

